class Solution {
public:
    long long maximumTripletValue(vector<int>& nums) {
        int n = nums.size();
        vector<int> prefixMax(n), suffixMax(n), prefixMin(n), suffixMin(n);
        prefixMax[0] = nums[0];
        prefixMin[0] = nums[0];
        for (int i = 1; i < n; i++) {
            prefixMax[i] = max(prefixMax[i - 1], nums[i]);
            prefixMin[i] = min(prefixMin[i - 1], nums[i]);
        }
        suffixMax[n - 1] = nums[n - 1];
        suffixMin[n - 1] = nums[n - 1];
        for (int i = n - 2; i >= 0; i--) {
            suffixMax[i] = max(suffixMax[i + 1], nums[i]);
            suffixMin[i] = min(suffixMin[i + 1], nums[i]);
        }
        long long res = LLONG_MIN;
        for (int j = 1; j < n - 1; j++) {
            long long val1 = (long long)(prefixMax[j - 1] - nums[j]) * suffixMax[j + 1];
            long long val2 = (long long)(prefixMax[j - 1] - nums[j]) * suffixMin[j + 1];
            long long val3 = (long long)(prefixMin[j - 1] - nums[j]) * suffixMax[j + 1];
            long long val4 = (long long)(prefixMin[j - 1] - nums[j]) * suffixMin[j + 1];
            res = max(res, max(max(val1, val2), max(val3, val4)));
        }
        return max(res, 0LL);
    }
};
